Tab Creation.query:
SELECT COUNT(*) FROM teams_channel_tabs 
WHERE display_name = 'Mission Control' 
  AND channel_id = (SELECT channel_id FROM channels WHERE display_name = 'Strategy');

Channel Membership.query:
SELECT COUNT(*) FROM channel_members 
WHERE channel_id = (SELECT channel_id FROM channels WHERE display_name = 'Strategy')
  AND user_id IN ('alice.johnson', 'james.wilson');
